import{_ as i,c as a,o,ak as t}from"./chunks/framework.CYxz2ou1.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoMind/B-知识库/文档规范.md","filePath":"NanoMind/B-知识库/文档规范.md","lastUpdated":1775467143000}'),r={name:"NanoMind/B-知识库/文档规范.md"};function e(n,l,p,s,d,u){return o(),a("div",null,[...l[0]||(l[0]=[t('<h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>技术学习必问：</p><ul><li>怎么用? 先学会用，再学习原理。</li><li>使用场景是什么? 知道可以用在什么地方。</li><li>最佳实践?</li><li>工作中用到了吗? 工作中如果用到了，理解可能会更深。</li><li>是否存在什么问题? 是否有缺陷? 是否有替代的方案。</li><li>实现原理是啥?</li></ul><p>笔记整理原则：</p><ul><li>尽量减少标题，特别是无用的标题，比如：总结，开篇词这种。</li><li>重要的部分在对应的章节上打上星号。</li><li>使用英文的标点符号。</li><li>Java 方法名后应该有 <code>()</code>，方法名加粗时将 <code>()</code> 也加粗。</li></ul><h2 id="图标" tabindex="-1">图标 <a class="header-anchor" href="#图标" aria-label="Permalink to &quot;图标&quot;">​</a></h2><ul><li>📘：目录</li><li>🍀：整理中</li><li>🌸：已完成整理</li><li>🌟：重要章节或内容</li></ul><h2 id="颜色" tabindex="-1">颜色 <a class="header-anchor" href="#颜色" aria-label="Permalink to &quot;颜色&quot;">​</a></h2><ul><li><strong>二级</strong>：#0d007e</li><li><strong>三级</strong>：#00578E</li><li><strong>四级</strong>：默认红色</li><li><strong>普通</strong>：#025420 对应前面的引用块：</li></ul><h2 id="路线" tabindex="-1">路线 <a class="header-anchor" href="#路线" aria-label="Permalink to &quot;路线&quot;">​</a></h2><p><strong>整理已有的笔记资料</strong></p><ul><li>已经完成的章节文件标记为 🌸。</li><li>重要章节的标题后需要加上 🌟。</li><li>如果一个大类也完成整理那就文件夹名上加上 🌸。</li><li><strong>用不到的一定要删掉。没用的东西删掉。拒绝又臭又长的内容</strong>。</li><li>过时的内容相关的细节也删掉，不过可以记录一下历史发展和淘汰原因。</li></ul><p><strong>看书</strong></p><ul><li>一定要先找找有没有对应的 EPUB 版本，方便复制出来内容。</li></ul><p><strong>如何选择接下来应该学什么?</strong></p><ul><li>对该内容有刚需，所做工作正好有涉及。</li><li>有用的帖子及时整理。</li></ul><p><strong>谨记</strong></p><ul><li>需要自己补充一下各个知识点之间的关联，发展脉络，理解比记忆更重要。</li></ul><h2 id="利用思源笔记导入-epub" tabindex="-1">利用思源笔记导入 Epub <a class="header-anchor" href="#利用思源笔记导入-epub" aria-label="Permalink to &quot;利用思源笔记导入 Epub&quot;">​</a></h2><p>思源笔记安装导入插件。导入时先删除垃圾文件。</p><p>![[文档规范-1775305320963.png|776x258]]</p><p>导入到思源笔记后，选择导出 <code>Markdown.zip</code>：</p><p>![[文档规范-1775305418792.png|334x589]]</p><p>语雀进行导入，选择导入 Markdown 打包后的压缩文件：</p><p>![[文档规范-1775305442167.png|351x530]]</p><p>即可导入。</p><p>注意：对于极客时间的 Epub，有的导入之后图片上下有两行 HTML 的数据，需要先删掉再从思源导出 ZIP，不然语雀会因为这些 HTML 解析得格式混乱。</p><p>![[文档规范-1775305463671.png]]</p><h2 id="批量导入极客时间" tabindex="-1">批量导入极客时间 <a class="header-anchor" href="#批量导入极客时间" aria-label="Permalink to &quot;批量导入极客时间&quot;">​</a></h2><p>极客时间专栏如有有 Markdown 文件合集，只需要先<strong>整个压缩为一个 ZIP 文件</strong>，然后再导入即可。</p><p>注意：<strong>HTML 格式的极客时间无法导入，导入后无法编辑</strong>。</p>',31)])])}const g=i(r,[["render",e]]);export{c as __pageData,g as default};
